content.content:
diff --git a/src/style.css b/src/style.css
index 5f348e7..78fc724 100644
--- a/src/style.css
+++ b/src/style.css
@@ -153,19 +153,19 @@ html, body {
 }
 #island-pin .pin-svg { display: block; }
 #island-pin .pin-svg path {
-  fill: var(--accent-warm);
-  stroke: rgba(255, 244, 232, 0.85);
+  fill: var(--accent);
+  stroke: rgba(255, 255, 255, 0.9);
   stroke-width: 1.2;
 }
 #island-pin .pin-svg circle {
-  fill: rgba(20, 12, 6, 0.85);
+  fill: rgba(6, 16, 26, 0.9);
 }
 /* Hover (or keyboard focus, or synced from the 3D region) lifts the pin. */
 #island-pin:hover,
 #island-pin:focus-visible,
 #island-pin.is-hot {
   transform: translate(-50%, -100%) scale(1.12);
-  filter: drop-shadow(0 0 10px rgba(255, 184, 107, 0.6));
+  filter: drop-shadow(0 0 10px rgba(111, 227, 255, 0.65));
   outline: none;
 }

